function worked_http_server_ts_testing_contracts_fuzz_4(domainCases: number, handlerCases: number, fuzzFailures: number, leakedResources: number): { release: boolean; gate: string } {
  if (domainCases < 3) return { release: false, gate: "domain" };
  if (handlerCases < 3) return { release: false, gate: "handler" };
